import { execSync } from "child_process";
import fs from "fs";
function putText(n,s){const repo=process.env.GH_REPO,tok=process.env.GH_TOKEN;const url='https://api.github.com/repos/'+repo+'/contents/analize/'+n;let sha='';try{sha=JSON.parse(execSync('curl -s --max-time 30 -H "Authorization: Bearer '+tok+'" "'+url+'?ref=main&t='+Date.now()+'"',{encoding:'utf8'})).sha||'';}catch(e){}const b={message:'x',branch:'main',content:Buffer.from(s,'utf8').toString('base64')};if(sha)b.sha=sha;fs.writeFileSync('/tmp/pf.json',JSON.stringify(b));execSync('curl -s --max-time 40 -X PUT -H "Authorization: Bearer '+tok+'" -d @/tmp/pf.json "'+url+'"',{encoding:'utf8'});}
const BASE='https://dev.avesa.lt';const U=process.env.WP_USER||'';const P=(process.env.WP_APP_PASS||'').replace(/\s+/g,'');
function api(method,path,body){const auth='-u "'+U+':'+P+'"';let cmd;if(body){fs.writeFileSync('/tmp/b.json',JSON.stringify(body));cmd='curl -s -k --max-time 90 -w "\nHTTP:%{http_code}" '+auth+' -X '+method+' -H "Content-Type: application/json" --data-binary @/tmp/b.json "'+BASE+path+'"';}else{cmd='curl -s -k --max-time 60 -w "\nHTTP:%{http_code}" '+auth+' -X '+method+' "'+BASE+path+'"';}let r;try{r=execSync(cmd,{encoding:'utf8',maxBuffer:30000000});}catch(e){r=(e.stdout||'')+'\nHTTP:TIMEOUT';}return{code:(r.match(/HTTP:(\S+)$/)||[])[1]||'?',body:r.replace(/\nHTTP:\S+$/,'')};}
function sh(c){try{return execSync(c,{encoding:'utf8',maxBuffer:30000000});}catch(e){return (e.stdout||'')+'[ERR]';}}
const MAIN='', IFACE='', ELOG='', CLOG='', CSYNC='', RETRY='';
(async()=>{
  let out=''; const L=s=>{out+=s+'\n'; console.log(s);};
  L('=== petshop-core plugin deploy ===');

  const deployPHP = "if(!defined('ABSPATH'))return;\n" +
    "add_action('wp_loaded', function(){\n" +
    "  if(($_GET['ps_deploy_core']??'')!=='1')return;\n" +
    "  if(($_GET['token']??'')!=='cmplz_6680aa2a42151d54fa8d64ec')return;\n" +
    "  $dir = WP_PLUGIN_DIR . '/petshop-core';\n" +
    "  $inc = $dir . '/includes';\n" +
    "  if(!is_dir($dir)) mkdir($dir, 0755, true);\n" +
    "  if(!is_dir($inc)) mkdir($inc, 0755, true);\n" +
    "  $out = array();\n" +
    "  $out['main'] = @file_put_contents($dir.'/petshop-core.php', base64_decode('" + MAIN + "'));\n" +
    "  $out['iface'] = @file_put_contents($inc.'/interface-message-provider.php', base64_decode('" + IFACE + "'));\n" +
    "  $out['event_log'] = @file_put_contents($inc.'/class-event-log.php', base64_decode('" + ELOG + "'));\n" +
    "  $out['consent_log'] = @file_put_contents($inc.'/class-consent-log.php', base64_decode('" + CLOG + "'));\n" +
    "  $out['consent_sync'] = @file_put_contents($inc.'/class-consent-sync.php', base64_decode('" + CSYNC + "'));\n" +
    "  $out['retry'] = @file_put_contents($inc.'/class-retry-queue.php', base64_decode('" + RETRY + "'));\n" +
    "  header('Content-Type: application/json'); echo wp_json_encode($out, JSON_PRETTY_PRINT); exit;\n" +
    "}, 6);";
  const c = api('POST','/wp-json/code-snippets/v1/snippets',{name:'Petshop Core Deploy tmp',desc:'token',code:deployPHP,scope:'global',active:true,priority:5});
  let sid=0; try{sid=JSON.parse(c.body).id;}catch(e){}
  L('deploy snippet id: '+sid);
  if(!sid){ L('fail: '+c.body.slice(0,200)); putText('core_deploy.txt',out); return; }
  execSync('sleep 2');
  const r = sh('curl -s -k --max-time 40 "'+BASE+'/?ps_deploy_core=1&token=cmplz_6680aa2a42151d54fa8d64ec"');
  L('deploy result:'); L(r);
  api('POST','/wp-json/code-snippets/v1/snippets/'+sid+'/deactivate',{});

  // Aktyvuoti plugin
  const actPHP = "if(!defined('ABSPATH'))return;\n" +
    "add_action('wp_loaded', function(){\n" +
    "  if(($_GET['ps_act_core']??'')!=='1')return;\n" +
    "  if(($_GET['token']??'')!=='cmplz_6680aa2a42151d54fa8d64ec')return;\n" +
    "  if(!function_exists('activate_plugin')) require_once ABSPATH.'wp-admin/includes/plugin.php';\n" +
    "  $slug='petshop-core/petshop-core.php';\n" +
    "  $err = activate_plugin($slug);\n" +
    "  $out = array(\n" +
    "    'activated'=>is_plugin_active($slug),\n" +
    "    'error'=>is_wp_error($err)?$err->get_error_message():null,\n" +
    "    'core_version'=>defined('PETSHOP_CORE_VERSION')?PETSHOP_CORE_VERSION:'?',\n" +
    "    'esp_still_active'=>is_plugin_active('petshop-esp/petshop-esp.php'),\n" +
    "    'esp_version'=>defined('PETSHOP_ESP_VERSION')?PETSHOP_ESP_VERSION:'?',\n" +
    "    'classes'=>array(\n" +
    "      'Petshop_Event_Log'=>class_exists('Petshop_Event_Log'),\n" +
    "      'Petshop_Consent_Log'=>class_exists('Petshop_Consent_Log'),\n" +
    "      'Petshop_Consent_Sync'=>class_exists('Petshop_Consent_Sync'),\n" +
    "      'Petshop_Retry_Queue'=>class_exists('Petshop_Retry_Queue'),\n" +
    "      'Petshop_Message_Provider'=>interface_exists('Petshop_Message_Provider'),\n" +
    "      // sena esp klases turi ir toliau egzistuoti (esp v0.3.0 dar gyvas)\n" +
    "      'Petshop_ESP_Event_Log'=>class_exists('Petshop_ESP_Event_Log'),\n" +
    "      'Petshop_ESP_Consent_Log'=>class_exists('Petshop_ESP_Consent_Log'),\n" +
    "    ),\n" +
    "    'functions'=>array(\n" +
    "      'ps_emit_event'=>function_exists('ps_emit_event'),\n" +
    "      'ps_set_marketing_consent'=>function_exists('ps_set_marketing_consent'),\n" +
    "      'ps_esp_adapter'=>function_exists('ps_esp_adapter'),\n" +
    "    ),\n" +
    "  );\n" +
    "  header('Content-Type: application/json'); echo wp_json_encode($out, JSON_PRETTY_PRINT); exit;\n" +
    "}, 6);";
  const c2 = api('POST','/wp-json/code-snippets/v1/snippets',{name:'Petshop Core Act tmp',desc:'token',code:actPHP,scope:'global',active:true,priority:5});
  let sid2=0; try{sid2=JSON.parse(c2.body).id;}catch(e){}
  execSync('sleep 2');
  const r2 = sh('curl -s -k --max-time 40 "'+BASE+'/?ps_act_core=1&token=cmplz_6680aa2a42151d54fa8d64ec"');
  L('activate result:'); L(r2);
  api('POST','/wp-json/code-snippets/v1/snippets/'+sid2+'/deactivate',{});

  putText('core_deploy.txt', out);
})();
